## TabBar Component

The `TabBar` component provides a UI element for managing and switching between multiple tabs.

### Purpose

This component renders a horizontal bar containing a list of tabs. Users can click on a tab to make it active, close tabs (if more than one exists), and add new tabs.

### Key Exports

*   `TabBar`: A React functional component that renders the tab bar.

### Props

*   `tabs` (Array<`Tab`>): An array of objects, where each object represents a tab. Each `Tab` object should have at least an `id` (string) and a `label` (string).
*   `activeTabId` (string): The ID of the currently active tab.
*   `onSwitch` (function(id: string) => void): A callback function that is invoked when a tab is clicked to switch to it. It receives the `id` of the tab to switch to.
*   `onClose` (function(id: string) => void): A callback function that is invoked when a tab's close button is clicked or when the middle mouse button is used on a tab. It receives the `id` of the tab to close.
*   `onAdd` (function() => void): A callback function that is invoked when the "New tab" button is clicked.

### Usage Example

```tsx
import React, { useState } from 'react';
import { TabBar } from './TabBar';
import type { Tab } from './types';

function App() {
  const [tabs, setTabs] = useState<Tab[]>([
    { id: 'tab1', label: 'Tab 1' },
    { id: 'tab2', label: 'Tab 2' },
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('tab1');
  const [nextTabId, setNextTabId] = useState<number>(3);

  const handleSwitchTab = (id: string) => {
    setActiveTabId(id);
  };

  const handleCloseTab = (id: string) => {
    setTabs(tabs.filter(tab => tab.id !== id));
    // If the closed tab was active, switch to another tab
    if (activeTabId === id && tabs.length > 1) {
      setActiveTabId(tabs.find(tab => tab.id !== id)?.id || '');
    } else if (tabs.length === 1) {
      setActiveTabId('');
    }
  };

  const handleAddTab = () => {
    const newTabId = `tab${nextTabId}`;
    setTabs([...tabs, { id: newTabId, label: `Tab ${nextTabId}` }]);
    setActiveTabId(newTabId);
    setNextTabId(prev => prev + 1);
  };

  return (
    <div>
      <TabBar
        tabs={tabs}
        activeTabId={activeTabId}
        onSwitch={handleSwitchTab}
        onClose={handleCloseTab}
        onAdd={handleAddTab}
      />
      {/* Content for the active tab would go here */}
      <div>Current active tab: {activeTabId}</div>
    </div>
  );
}

export default App;
```
